package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;import java.util.*;
public class GraphView extends View{Paint p=new Paint(1);ArrayList<Float> vals=new ArrayList<>(); public GraphView(Context c){super(c);} public void add(float v){vals.add(v);if(vals.size()>90)vals.remove(0);invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight();p.setColor(Color.rgb(12,22,38));c.drawRoundRect(0,0,w,h,24,24,p);p.setColor(Color.argb(55,255,255,255));p.setStrokeWidth(1);for(int i=1;i<5;i++)c.drawLine(0,h*i/5,w,h*i/5,p); if(vals.size()<2)return;float max=1;for(float v:vals)max=Math.max(max,v);p.setColor(Color.rgb(0,220,255));p.setStrokeWidth(5);Path path=new Path();for(int i=0;i<vals.size();i++){float x=i*w/(float)89;float y=h-(vals.get(i)/max)*h*.85f-10;if(i==0)path.moveTo(x,y);else path.lineTo(x,y);}c.drawPath(path,p);}}
